description:
# Task

Add property-based tests ensuring ToBamlValue and BamlValueConvert are true inverses.

## File to Create
`baml-bridge/crates/bridge/tests/to_value_roundtrip.rs`

## Test Strategy

For every type that implements both ToBamlValue and BamlValueConvert:
```rust
let original: T = /* arbitrary value */;
let baml_value = original.to_baml_value();
let recovered = T::try_from_baml_value(baml_value).unwrap();
assert_eq!(original, recovered);
```

## Test Cases

### Primitives
```rust
#[test]
fn roundtrip_string() {
    let values = vec![
        "".to_string(),
        "hello".to_string(),
        "with\nnewline".to_string(),
        "unicode: 日本語".to_string(),
    ];
    for s in values {
        let baml = s.to_baml_value();
        let recovered = String::try_from_baml_value(baml, vec![]).unwrap();
        assert_eq!(s, recovered);
    }
}

#[test]
fn roundtrip_numbers() {
    // Test edge cases: 0, negatives, max values
    for i in [0i32, 1, -1, i32::MAX, i32::MIN] {
        let baml = i.to_baml_value();
        let recovered = i32::try_from_baml_value(baml, vec![]).unwrap();
        assert_eq!(i, recovered);
    }
}
```

### Containers
```rust
#[test]
fn roundtrip_option() {
    let some: Option<i32> = Some(42);
    let none: Option<i32> = None;

    // Some case
    let baml = some.to_baml_value();
    let recovered = Option::<i32>::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(some, recovered);

    // None case
    let baml = none.to_baml_value();
    let recovered = Option::<i32>::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(none, recovered);
}

#[test]
fn roundtrip_vec() {
    let vec: Vec<String> = vec!["a".into(), "b".into()];
    let baml = vec.to_baml_value();
    let recovered = Vec::<String>::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(vec, recovered);
}
```

### Structs
```rust
#[derive(BamlType, Debug, PartialEq)]
struct TestStruct {
    name: String,
    count: i32,
    tags: Vec<String>,
    meta: Option<String>,
}

#[test]
fn roundtrip_struct() {
    let original = TestStruct {
        name: "test".into(),
        count: 42,
        tags: vec!["a".into()],
        meta: Some("info".into()),
    };
    let baml = original.to_baml_value();
    let recovered = TestStruct::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(original, recovered);
}
```

### Enums
```rust
#[derive(BamlType, Debug, PartialEq)]
enum TestEnum {
    Unit,
    WithData { value: i32 },
}

#[test]
fn roundtrip_unit_enum() {
    let original = TestEnum::Unit;
    let baml = original.to_baml_value();
    let recovered = TestEnum::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(original, recovered);
}

#[test]
fn roundtrip_data_enum() {
    let original = TestEnum::WithData { value: 42 };
    let baml = original.to_baml_value();
    let recovered = TestEnum::try_from_baml_value(baml, vec![]).unwrap();
    assert_eq!(original, recovered);
}
```

## Property-Based Testing (Optional but Recommended)

Consider using `proptest` or `quickcheck`:
```rust
proptest! {
    #[test]
    fn roundtrip_arbitrary_struct(
        name in ".*",
        count in any::<i32>(),
    ) {
        let original = TestStruct { name, count, tags: vec![], meta: None };
        let baml = original.to_baml_value();
        let recovered = TestStruct::try_from_baml_value(baml, vec![]).unwrap();
        prop_assert_eq!(original, recovered);
    }
}
```

